parameters.jsCode:
// Gemini returns: {candidates: [{content: {parts: [{text: "<json>"}]}}], ...}
// With responseMimeType="application/json" the text IS a JSON string, but parse defensively.

const out = [];
const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const resp = items[i].json;
  const text = resp?.candidates?.[0]?.content?.parts?.[0]?.text;
  if (!text) {
    console.log('No text in Gemini response for item', i, JSON.stringify(resp).slice(0, 500));
    continue;
  }
  let parsed;
  try {
    parsed = JSON.parse(text);
  } catch (e) {
    // Sometimes models wrap JSON in code fences despite instructions
    const stripped = text.replace(/^```json\s*/, '').replace(/```\s*$/, '');
    try { parsed = JSON.parse(stripped); }
    catch (e2) {
      console.log('Failed to parse Gemini JSON:', text.slice(0, 500));
      continue;
    }
  }

  // Bring forward clip metadata via paired item from Carry Metadata
  const meta = $('Carry Metadata').itemMatching(i)?.json || {};

  out.push({
    pairedItem: { item: i },
    json: {
      clip_id: meta.clip_id,
      broadcaster_login: meta.broadcaster_login,
      drive_file_id: meta.drive_file_id,
      drive_file_name: meta.drive_file_name,
      virality: parsed.virality,
      captions: parsed.captions,
      content_analysis: parsed.content_analysis,
      // Flatten the most-queried fields for easier downstream filtering
      ai_virality_score: parsed.virality?.score,
      ai_audience_fit: parsed.virality?.audience_fit,
      ai_emotion_type: parsed.virality?.emotion_type,
      ai_hook_strength: parsed.virality?.hook_strength,
      ai_reasoning: parsed.virality?.reasoning,
      ai_recommended_for_publish: parsed.virality?.recommended_for_publish === true,
    }
  });
}
return out;

// Set ready_for_publish flag based on score threshold + AI recommendation.
// We still store the analysis + captions for ALL clips so a human can review the borderline ones.
const THRESHOLD = $('Config1').isExecuted
  ? ($('Config1').first().json.PUBLISH_THRESHOLD || 7)
  : 7;
return $input.all().map(item => ({
  pairedItem: item.pairedItem,
  json: {
    ...item.json,
    ready_for_publish: (item.json.ai_virality_score >= THRESHOLD) && (item.json.ai_recommended_for_publish === true),
  }
}));

const row = $('Supabase Webhook').first().json.body.record;
let c = row.captions || {};
if (typeof c === 'string') {
  try { c = JSON.parse(c); } catch (e) { c = {}; }
}

function clean(s) { return (s || '').trim(); }

const tiktok_title    = clean(`${c.tiktok?.caption || ''}\n\n${c.tiktok?.hashtags || ''}`);
const instagram_title = clean(`${c.instagram_reels?.caption || ''}\n\n${c.instagram_reels?.hashtags || ''}`);
const youtube_title   = clean(c.youtube_shorts?.title || row.title || 'Untitled');
const youtube_description = clean(c.youtube_shorts?.description || '');
const x_title         = clean(c.x_twitter?.post || '');

const rawTags = Array.isArray(c.youtube_shorts?.tags) ? c.youtube_shorts.tags : [];
const youtube_tags = rawTags
  .map(t => String(t || '').toLowerCase().replace(/^#/, '').trim())
  .filter(Boolean)
  .slice(0, 10);

return [{
  json: {
    clip_id: row.clip_id,
    broadcaster_login: row.broadcaster_login,
    video_url: row.rendered_url,
    tiktok_title,
    instagram_title,
    youtube_title,
    youtube_description,
    youtube_tags,
    x_title,
  }
}];

const raw = $input.first().json;
const resp = raw.body || raw;
const upstream = $('Build Upload Fields').first().json;

const isAsync = !!resp.request_id && !resp.results;
const results = resp.results || {};
const platformStatus = {};
for (const p of ['tiktok', 'instagram', 'youtube', 'twitter', 'x']) {
  if (results[p]) platformStatus[p] = { success: results[p].success === true, url: results[p].url, error: results[p].error };
}

return [{
  json: {
    clip_id: upstream.clip_id,
    upload_post_response: resp,
    upload_post_request_id: resp.request_id || null,
    is_async: isAsync,
    overall_success: resp.success === true,
    per_platform: platformStatus,
  }
}];

// 429 — fan out 1 item per platform with an action.
// Actions:
//   'post'  — not in any violation list, try solo retry
//   'defer' — known capped (from 429 body), skip API call, record retry_after
//   'skip'  — non-cap violation type (duplicate, mentions)
//   'queue' — only as a no-platform-info fallback; rarely fires
//
// upload-post's queue endpoint shares the pre-flight cap gate with the
// immediate-post endpoint, so calling queue for a known-capped platform
// just burns a request. Defer it and let a reconcile workflow retry later.

const httpResp = $('Post to All Platforms').first().json;
const body = httpResp.body || httpResp;
const upstream = $('Build Upload Fields').first().json;

const ALL_PLATFORMS = ['tiktok', 'instagram', 'youtube', 'x'];
const hardCapped = new Set();
const otherViolated = new Map();

// Shape A: flat top-level platform info
if (body.platform && (body.cap != null || body.used_last_24h != null)) {
  hardCapped.add(body.platform);
}

// Shape B: violations array
if (Array.isArray(body.violations)) {
  for (const v of body.violations) {
    if (!v || !v.platform) continue;
    if (v.type === 'hard_cap') hardCapped.add(v.platform);
    else otherViolated.set(v.platform, v);
  }
}

const haveAnyPlatformInfo = hardCapped.size > 0 || otherViolated.size > 0;

const items = [];
for (const platform of ALL_PLATFORMS) {
  let action, reason, violation = null;

  if (hardCapped.has(platform)) {
    action = 'defer';
    reason = body.message || `${platform}: hard cap reached`;
    violation = { type: 'hard_cap', platform, used_last_24h: body.used_last_24h, cap: body.cap };
  } else if (otherViolated.has(platform)) {
    const v = otherViolated.get(platform);
    action = 'skip';
    reason = v.message || `${platform}: ${v.type}`;
    violation = v;
  } else if (!haveAnyPlatformInfo) {
    // No identifiable platform — try the queue endpoint as a fallback.
    action = 'queue';
    reason = 'rate_limited_no_platform_detail';
  } else {
    action = 'post';
    reason = null;
  }

  items.push({
    json: { ...upstream, platform, action, reason, violation },
  });
}

return items;

// Non-429 response from the solo retry: 2xx sync success, 2xx async-started, or some failure.
const planItem = $('Plan Recovery').item.json;
const raw = $input.item.json;
const body = raw.body || raw;
const status = raw.statusCode ?? null;

const platform = planItem.platform;
const result = (body && body.results && body.results[platform]) || null;

// Two success shapes from upload-post:
//   sync done:     { success: true, results: { [platform]: { success: true, url } } }
//   async started: { success: true, request_id, total_platforms }  ← was being misread as failure
const syncSuccess  = body?.success === true && result?.success === true;
const asyncStarted = body?.success === true && !!body?.request_id && !body?.results;
const success      = syncSuccess || asyncStarted;

return {
  json: {
    platform,
    outcome: success ? 'posted' : 'post_failed',
    status_code: status,
    is_async: asyncStarted,
    request_id: body?.request_id || null,
    url: result?.url || null,
    error: success ? null : (result?.error || body?.message || body?.error || `status ${status}`),
    response: body,
  }
};

// Parse the per-platform queue response.
// Possible outcomes:
//   202 + job_id  -> 'queued'
//   429 + body.platform info -> 'cap_rejected' (with retry_after)
//   other failure -> 'queue_failed'
const planItem = $('Plan Recovery').item.json;
const raw = $input.item.json;
const body = raw.body || raw;
const status = raw.statusCode ?? null;

const cfg = $('Config2').first().json;
const DEFER_HOURS = Number(cfg.DEFER_HOURS) || 24;
const DEFER_BUFFER_MINUTES = Number(cfg.DEFER_BUFFER_MINUTES) || 10;

const success = body?.success === true && !!body?.job_id;
const capRejected = !success && status === 429 && !!body?.platform;

let retry_after = null;
if (capRejected) {
  retry_after = DateTime.utc()
    .plus({ hours: DEFER_HOURS, minutes: DEFER_BUFFER_MINUTES })
    .toISO();
}

let outcome;
if (success) outcome = 'queued';
else if (capRejected) outcome = 'cap_rejected';
else outcome = 'queue_failed';

return [{
  json: {
    platform: planItem.platform,
    outcome,
    status_code: status,
    job_id: body?.job_id || null,
    scheduled_date: body?.scheduled_date || body?.queue_slot || null,
    retry_after,
    cap_info: capRejected
      ? { used_last_24h: body.used_last_24h, cap: body.cap, message: body.message }
      : null,
    error: success ? null : (body?.message || body?.error || `status ${status}`),
    reason_for_queueing: planItem.reason,
    response: body,
  }
}];

// Mark a platform as deferred — no API call needed. Handles inputs from:
//   (a) Switch By Action 'defer' output — input is the plan item directly
//   (b) Post Capped? true output — input is the 429 HTTP response
const planItem = $('Plan Recovery').item.json;
const raw = $input.item.json;
const isHttpResponse = raw?.statusCode !== undefined || raw?.body !== undefined;
const body = isHttpResponse ? (raw.body || null) : null;

const cfg = $('Config2').first().json;
const DEFER_HOURS = Number(cfg.DEFER_HOURS) || 24;
const DEFER_BUFFER_MINUTES = Number(cfg.DEFER_BUFFER_MINUTES) || 10;

const retry_after = DateTime.utc()
  .plus({ hours: DEFER_HOURS, minutes: DEFER_BUFFER_MINUTES })
  .toISO();

const cap_info = body?.used_last_24h != null
  ? { used_last_24h: body.used_last_24h, cap: body.cap, message: body.message }
  : (planItem.violation?.used_last_24h != null
      ? { used_last_24h: planItem.violation.used_last_24h, cap: planItem.violation.cap, message: planItem.reason }
      : null);

return [{
  json: {
    platform: planItem.platform,
    outcome: 'deferred',
    reason: planItem.reason || body?.message || 'platform_capped',
    retry_after,
    cap_info,
    via: isHttpResponse ? 'post_failover' : 'plan_known_cap',
  }
}];

// Skip path — non-cap violation. Pass through as a 'skipped' result, no API call.
return [{
  json: {
    platform: $json.platform,
    outcome: 'skipped',
    reason: $json.reason,
    violation: $json.violation,
  }
}];

// Combine all per-platform outcomes into a single Supabase update payload.
const all = $input.all().map(i => i.json);
const upstream = $('Build Upload Fields').first().json;

const posted = [];
const queued = [];
const deferred = [];
const cap_rejected = [];
const failed = [];
const skipped = [];

for (const r of all) {
  if (r.outcome === 'posted') {
    posted.push({ platform: r.platform, url: r.url });
  } else if (r.outcome === 'queued') {
    queued.push({ platform: r.platform, job_id: r.job_id, scheduled_date: r.scheduled_date, reason: r.reason_for_queueing });
  } else if (r.outcome === 'deferred') {
    deferred.push({ platform: r.platform, retry_after: r.retry_after, reason: r.reason, cap_info: r.cap_info, via: r.via });
  } else if (r.outcome === 'cap_rejected') {
    cap_rejected.push({ platform: r.platform, retry_after: r.retry_after, cap_info: r.cap_info });
  } else if (r.outcome === 'skipped') {
    skipped.push({ platform: r.platform, reason: r.reason });
  } else {
    failed.push({ platform: r.platform, outcome: r.outcome, error: r.error });
  }
}

// Earliest pending datetime across queued.scheduled_date + deferred.retry_after + cap_rejected.retry_after
let earliest = null;
const candidates = [
  ...queued.map(q => q.scheduled_date).filter(Boolean),
  ...deferred.map(d => d.retry_after).filter(Boolean),
  ...cap_rejected.map(c => c.retry_after).filter(Boolean),
];
for (const d of candidates) {
  const dt = DateTime.fromISO(d, { zone: 'utc' });
  if (dt.isValid && (!earliest || dt < earliest)) earliest = dt;
}

const recovery_state = {
  posted,
  queued,
  deferred,
  cap_rejected,
  failed,
  skipped,
  evaluated_at: DateTime.now().toUTC().toISO(),
};

const hasPending = queued.length > 0 || deferred.length > 0 || cap_rejected.length > 0;

return [{
  json: {
    clip_id: upstream.clip_id,
    posted_to_socials: true,
    scheduled_for_later: hasPending,
    scheduled_date: earliest ? earliest.toUTC().toISO() : null,
    scheduled_at: hasPending ? DateTime.now().toUTC().toISO() : null,
    upload_post_job_id: queued.length > 0 ? (queued[0].job_id || null) : null,
    recovery_state,
    posted_at: posted.length > 0 ? DateTime.now().toUTC().toISO() : null,
  }
}];

// For each pending clip, emit 1 item per platform that still needs to post.
// Platforms come from recovery_state.deferred + .cap_rejected + .failed.
// We pass the full clip context along so downstream nodes can reach back.

const cfg = $('Config3').first().json;
const MAX_ATTEMPTS = Number(cfg.MAX_ATTEMPTS_PER_PLATFORM) || 5;

const clips = $input.all().map(i => i.json);
const items = [];

for (const clip of clips) {
  // recovery_state may come back as string (JSONB-as-text) or already parsed.
  let rs = clip.recovery_state || {};
  if (typeof rs === 'string') {
    try { rs = JSON.parse(rs); } catch (e) { rs = {}; }
  }
  for (const b of ['posted', 'queued', 'deferred', 'cap_rejected', 'failed', 'skipped']) {
    if (!Array.isArray(rs[b])) rs[b] = [];
  }

  // Rebuild upload fields from the row's captions (same logic as Build Upload Fields in main).
  let c = clip.captions || {};
  if (typeof c === 'string') {
    try { c = JSON.parse(c); } catch (e) { c = {}; }
  }
  const clean = s => (s || '').trim();

  const uploadFields = {
    video_url: clip.rendered_url,
    tiktok_title: clean(`${c.tiktok?.caption || ''}\n\n${c.tiktok?.hashtags || ''}`),
    instagram_title: clean(`${c.instagram_reels?.caption || ''}\n\n${c.instagram_reels?.hashtags || ''}`),
    youtube_title: clean(c.youtube_shorts?.title || clip.title || 'Untitled'),
    youtube_description: clean(c.youtube_shorts?.description || ''),
    x_title: clean(c.x_twitter?.post || ''),
  };
  const rawTags = Array.isArray(c.youtube_shorts?.tags) ? c.youtube_shorts.tags : [];
  uploadFields.youtube_tags = rawTags
    .map(t => String(t || '').toLowerCase().replace(/^#/, '').trim())
    .filter(Boolean)
    .slice(0, 10);

  // Only retry platforms whose retry_after has actually elapsed AND who haven't exceeded MAX_ATTEMPTS.
  const now = DateTime.utc();
  const retryBuckets = [
    { name: 'deferred', entries: rs.deferred },
    { name: 'cap_rejected', entries: rs.cap_rejected },
    { name: 'failed', entries: rs.failed },
  ];

  for (const bucket of retryBuckets) {
    for (const entry of bucket.entries) {
      if (!entry || !entry.platform) continue;

      const attempts = entry.attempts || 0;
      if (attempts >= MAX_ATTEMPTS) continue; // give up after N tries

      // If the entry has a retry_after, respect it.
      if (entry.retry_after) {
        const ra = DateTime.fromISO(entry.retry_after, { zone: 'utc' });
        if (ra.isValid && ra > now) continue; // not due yet
      }

      items.push({
        json: {
          clip_id: clip.clip_id,
          platform: entry.platform,
          retry_reason: bucket.name,
          retry_entry: entry,
          existing_recovery_state: rs,
          ...uploadFields,
        },
      });
    }
  }
}

return items;

// Classify the retry response. Async-aware.
// Idempotency dedup: if the original solo POST already created a job, upload-post returns it here.
// That means a previously-async-misclassified TikTok will come back as 'posted' on the retry.

const target = $('Extract Retry Targets').item.json;
const raw = $input.item.json;
const body = raw.body || raw;
const status = raw.statusCode ?? null;

const cfg = $('Config3').first().json;
const BACKOFF_HOURS = Number(cfg.RETRY_BACKOFF_HOURS) || 24;
const BACKOFF_BUFFER = Number(cfg.RETRY_BACKOFF_BUFFER_MINUTES) || 10;

const platform = target.platform;
const result = (body && body.results && body.results[platform]) || null;

const syncSuccess  = body?.success === true && result?.success === true;
const asyncStarted = body?.success === true && !!body?.request_id && !body?.results;
const success      = syncSuccess || asyncStarted;
const capRejected  = !success && status === 429 && !!body?.platform;

let outcome;
let retry_after = null;
let error = null;

if (success) {
  outcome = 'posted';
} else if (capRejected) {
  outcome = 'cap_rejected';
  retry_after = DateTime.utc()
    .plus({ hours: BACKOFF_HOURS, minutes: BACKOFF_BUFFER })
    .toISO();
  error = body?.message || `status ${status}`;
} else {
  outcome = 'failed';
  retry_after = DateTime.utc()
    .plus({ hours: BACKOFF_HOURS, minutes: BACKOFF_BUFFER })
    .toISO();
  error = result?.error || body?.message || body?.error || `status ${status}`;
}

return [{
  json: {
    clip_id: target.clip_id,
    platform,
    retry_reason: target.retry_reason,
    retry_entry: target.retry_entry,
    existing_recovery_state: target.existing_recovery_state,
    outcome,
    status_code: status,
    is_async: asyncStarted,
    request_id: body?.request_id || null,
    url: result?.url || null,
    retry_after,
    cap_info: capRejected ? { used_last_24h: body.used_last_24h, cap: body.cap, message: body.message } : null,
    error,
  }
}];

// Group all per-platform retry results by clip_id, merge into each clip's
// existing recovery_state, and emit one update payload per clip.

const all = $input.all().map(i => i.json);
const byClip = new Map();
for (const r of all) {
  if (!byClip.has(r.clip_id)) byClip.set(r.clip_id, []);
  byClip.get(r.clip_id).push(r);
}

const out = [];

for (const [clipId, results] of byClip.entries()) {
  // existing_recovery_state is the same object on every result for this clip — pick any.
  const rs = JSON.parse(JSON.stringify(results[0].existing_recovery_state || {}));
  for (const b of ['posted', 'queued', 'deferred', 'cap_rejected', 'failed', 'skipped']) {
    if (!Array.isArray(rs[b])) rs[b] = [];
  }

  for (const r of results) {
    const platform = r.platform;
    const oldBucket = r.retry_reason; // 'deferred' | 'cap_rejected' | 'failed'

    // Pull the platform out of its old bucket.
    rs[oldBucket] = rs[oldBucket].filter(e => e.platform !== platform);

    const priorAttempts = (r.retry_entry && r.retry_entry.attempts) || 0;
    const nowIso = DateTime.utc().toISO();

    if (r.outcome === 'posted') {
      rs.posted.push({
        platform,
        url: r.url,
        via: 'reconcile',
        is_async: !!r.is_async,
        request_id: r.request_id || null,
        reconciled_at: nowIso,
      });
    } else if (r.outcome === 'cap_rejected') {
      rs.cap_rejected.push({
        platform,
        retry_after: r.retry_after,
        cap_info: r.cap_info,
        attempts: priorAttempts + 1,
        last_attempt_at: nowIso,
        last_attempt_error: r.error,
      });
    } else {
      rs.failed.push({
        platform,
        outcome: r.outcome,
        error: r.error,
        attempts: priorAttempts + 1,
        last_attempt_at: nowIso,
        retry_after: r.retry_after,
      });
    }
  }

  rs.evaluated_at = DateTime.utc().toISO();

  // Compute new earliest pending datetime across queued/deferred/cap_rejected/failed.
  let earliest = null;
  const candidates = [
    ...rs.queued.map(q => q.scheduled_date).filter(Boolean),
    ...rs.deferred.map(d => d.retry_after).filter(Boolean),
    ...rs.cap_rejected.map(c => c.retry_after).filter(Boolean),
    ...rs.failed.map(f => f.retry_after).filter(Boolean),
  ];
  for (const d of candidates) {
    const dt = DateTime.fromISO(d, { zone: 'utc' });
    if (dt.isValid && (!earliest || dt < earliest)) earliest = dt;
  }

  const hasPending =
    rs.queued.length + rs.deferred.length + rs.cap_rejected.length + rs.failed.length > 0;

  out.push({
    json: {
      clip_id: clipId,
      scheduled_for_later: hasPending,
      scheduled_date: earliest ? earliest.toUTC().toISO() : null,
      last_reconcile_at: DateTime.utc().toISO(),
      recovery_state: rs,
    },
  });
}

return out;

// Virality scoring (recency-weighted + duration sweet-spot bonus)
// MP4 URL is resolved downstream via Twitch GraphQL (thumbnail->mp4 trick
// stopped working for new-CDN clips, see "Resolve Clip MP4 URLs" node).

const MIN_VIEWS = $('Config').first().json.MIN_VIEWS;

const out = [];
for (const item of $input.all()) {
  const c = item.json;
  const created = new Date(c.created_at);
  const ageHours = Math.max(0.5, (Date.now() - created.getTime()) / 3.6e6);
  const velocity = c.view_count / ageHours;

  // Duration sweet-spot: peak score in [15, 45] seconds, falls off outside
  const dur = c.duration || 30;
  let durBonus;
  if (dur < 8) durBonus = 0.4;
  else if (dur <= 15) durBonus = 0.85;
  else if (dur <= 45) durBonus = 1.0;
  else if (dur <= 60) durBonus = 0.75;
  else durBonus = 0.4;

  // Composite score: velocity weighted heavily (recency), absolute views as tiebreaker
  const score = (velocity * 10 + c.view_count * 0.1) * durBonus;

  if (c.view_count < MIN_VIEWS) continue;

  out.push({
    json: {
      clip_id: c.id,
      broadcaster_login: c.broadcaster_name,
      broadcaster_id: c.broadcaster_id,
      title: c.title,
      game_id: c.game_id,
      url: c.url,
      embed_url: c.embed_url,
      view_count: c.view_count,
      duration: dur,
      created_at: c.created_at,
      age_hours: Number(ageHours.toFixed(2)),
      view_velocity: Number(velocity.toFixed(2)),
      duration_bonus: durBonus,
      virality_score: Number(score.toFixed(2)),
      thumbnail_url: c.thumbnail_url
    }
  });
}

out.sort((a, b) => b.json.virality_score - a.json.virality_score);
return out;

// Keep top N per broadcaster
const TOP_N = $('Config').first().json.TOP_N_PER_STREAMER;
const byStreamer = {};
for (const item of $input.all()) {
  const k = item.json.broadcaster_id;
  (byStreamer[k] = byStreamer[k] || []).push(item);
}
const kept = [];
for (const k of Object.keys(byStreamer)) {
  // already sorted desc by previous node
  kept.push(...byStreamer[k].slice(0, TOP_N));
}
return kept;

// Drop clip_ids that already exist in Supabase; keep the rest
const existingClipIds = new Set(
  $('Supabase: Already Processed?').all().map(i => i.json.clip_id).filter(Boolean)
);
const scored = $('Top N Per Streamer').all();
return scored.filter(item => !existingClipIds.has(item.json.clip_id));

// Pass each item back to Wait 30s individually, preserving the paired-item chain.
// Re-inject project_id (Get Status response uses 'project', not 'project_id') so the
// next Get Status URL expression keeps working.
// Cap at 10 polls (~5 min) to prevent infinite loops on stuck renders.

const runIdx = $runIndex || 0;
if (runIdx >= 9) {
  throw new Error('JSON2Video render did not complete after 10 polls (~5 min).');
}

return $input.all().map(item => ({
  pairedItem: item.pairedItem,
  json: {
    ...item.json,
    project_id: item.json.project || item.json.project_id,
  },
}));

// Pull top live streams, filter by min viewer count, cap at MAX, map to downstream shape.
// /helix/streams returns: {data: [{user_id, user_login, user_name, viewer_count, game_id, game_name, language, started_at, type, title}, ...]}

const data = $input.first().json.data || [];
const MIN = $('Build Context').first().json.min_live_viewers;
const MAX = $('Build Context').first().json.max_streamers;

const filtered = data
  .filter(s => s.type === 'live' && s.viewer_count >= MIN)
  .sort((a, b) => b.viewer_count - a.viewer_count)
  .slice(0, MAX);

return filtered.map(s => ({
  json: {
    // Map user_id -> id so the existing Get Clips Per Streamer node works unchanged
    id: s.user_id,
    user_id: s.user_id,
    login: s.user_login,
    display_name: s.user_name,
    viewer_count: s.viewer_count,
    game_id: s.game_id,
    game_name: s.game_name,
    language: s.language,
    stream_started_at: s.started_at,
    stream_title: s.title
  }
}));

// Resolve signed MP4 download URLs via Twitch's undocumented GraphQL.
// This is the same endpoint TwitchDownloader and similar tools use.
// kimne78kx3ncx6brgo4mv6wki5h1ko is Twitch's public web Client-Id (used by their own site).
// Stable for years; no user auth needed.

const GQL_URL = 'https://gql.twitch.tv/gql';
const TWITCH_WEB_CLIENT_ID = 'kimne78kx3ncx6brgo4mv6wki5h1ko';
const PERSISTED_HASH = '36b89d2507fce29e5ca551df756d27c1cfe079e2609642b4390aa4c35796eb11';

const out = [];
for (const item of $input.all()) {
  const slug = item.json.clip_id;
  if (!slug) continue;

  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: GQL_URL,
      headers: {
        'Client-Id': TWITCH_WEB_CLIENT_ID,
        'Content-Type': 'application/json',
      },
      body: [{
        operationName: 'VideoAccessToken_Clip',
        variables: { slug },
        extensions: {
          persistedQuery: {
            version: 1,
            sha256Hash: PERSISTED_HASH,
          },
        },
      }],
      json: true,
    });

    const clip = resp?.[0]?.data?.clip;
    if (!clip || !clip.videoQualities || !clip.videoQualities.length || !clip.playbackAccessToken) {
      // Clip might be deleted, private, or sub-only
      console.log('No qualities/token for clip:', slug);
      continue;
    }

    // Pick highest quality (sort desc by numeric quality e.g. "1080" > "720" > "480")
    const qualities = clip.videoQualities
      .slice()
      .sort((a, b) => parseInt(b.quality, 10) - parseInt(a.quality, 10));
    const best = qualities[0];

    const sig = clip.playbackAccessToken.signature;
    const token = clip.playbackAccessToken.value;
    const mp4_url = `${best.sourceURL}?sig=${sig}&token=${encodeURIComponent(token)}`;

    out.push({
      json: {
        ...item.json,
        mp4_url,
        mp4_quality: best.quality,
        mp4_framerate: best.frameRate,
      },
    });
  } catch (err) {
    console.log('Failed to resolve clip ' + slug + ':', err.message);
    // Skip this clip on failure
  }
}

return out;

// Normalize JSON2Video Get Status response.
// /v2/movies?project=X is documented to return {movie: {...}} (singular),
// but in practice can return the list shape {movies: [{...}, ...], has_next, ...}.
// This node finds our specific project in the list and exposes it as $json.movie
// so the Done? IF and downstream nodes work either way.
// Also preserves project_id for the polling loop.

const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const response = items[i].json || {};

  // Recover the project_id we polled for. After the first iteration, the
  // response shape may not have `project` at the top level, so we walk back
  // through the paired-item chain to Carry Project Ref.
  let targetProjectId = items[i].json?.project_id || items[i].json?.project;
  if (!targetProjectId) {
    try {
      targetProjectId = $('Carry Project Ref').itemMatching(i)?.json?.project_id;
    } catch (e) {
      // pairedItem chain broken; movie will be null and the item will loop
    }
  }

  // Find our movie in either response shape
  let movie = null;
  if (response.movie) {
    movie = response.movie;
  } else if (Array.isArray(response.movies) && targetProjectId) {
    movie = response.movies.find(m => m.project === targetProjectId) || null;
  }

  out.push({
    pairedItem: items[i].pairedItem,
    json: {
      success: response.success,
      movie,
      project: targetProjectId,
      project_id: targetProjectId,
    },
  });
}
return out;

// Filename format from main workflow: {broadcaster_login}_{clip_id}.mp4
// Split on FIRST underscore. Twitch clip slugs CAN contain underscores
// (e.g. "FancyKindFrogChocolateRain-24tkhXyJRr_-PbeI"), so we cannot split
// from the right side. Broadcaster logins almost never contain underscores
// in practice, so first-underscore is reliable.
// Recovery filenames have a "recovered_" prefix we strip first.

const out = [];
for (const item of $input.all()) {
  const drive = $('New File in Clips Folder').itemMatching($input.all().indexOf(item))?.json || item.json;
  let name = drive.name || '';
  const stem = name.replace(/\.mp4$/i, '').replace(/^recovered_/, '');
  const firstUnderscore = stem.indexOf('_');
  if (firstUnderscore < 1) {
    console.log('Filename pattern unexpected, skipping:', name);
    continue;
  }
  const broadcaster_login = stem.substring(0, firstUnderscore);
  const clip_id = stem.substring(firstUnderscore + 1);
  out.push({
    json: {
      drive_file_id: drive.id,
      drive_file_name: drive.name,
      broadcaster_login,
      clip_id,
    }
  });
}
return out;

// Merge Supabase row data with what we parsed from the filename
const out = [];
const sbRows = $input.all();
const parsedAll = $('Parse Filename').all();
for (let i = 0; i < sbRows.length; i++) {
  const sb = sbRows[i].json || {};
  const parsed = parsedAll[i]?.json || {};
  out.push({
    pairedItem: { item: i },
    json: {
      ...parsed,
      ...sb,
      drive_file_id: parsed.drive_file_id,
      drive_file_name: parsed.drive_file_name,
    }
  });
}
return out;

parameters.jsonBody:
={
  "contents": [
    {
      "parts": [
        {
          "inline_data": {
            "mime_type": "video/mp4",
            "data": "{{ $json.base64_video }}"
          }
        },
        {
          "text": "You are a viral clip captioner for Twitch content on TikTok, Instagram Reels, YouTube Shorts, and X. Audience: Gen Z (born 1997-2012) and Gen Alpha (born 2013+).

CLIP CONTEXT:
- Streamer: {{ $('Carry Metadata').item.json.broadcaster_login }}
- Original Twitch title: {{ $('Carry Metadata').item.json.title }}
- Twitch views: {{ $('Carry Metadata').item.json.view_count }}
- Internal virality score: {{ $('Carry Metadata').item.json.virality_score }}

# Step 1: Watch and describe SPECIFICALLY what happens

Don't skip this. Be concrete. Vague captions ("the chaotic energy is unmatched 💀") are AI tells — they apply to any clip and pull no engagement. Specific captions ("not him jumping when the volume hits at 0:13") actually convert.

Identify:
- What's visually on screen — if a meme/video/song is playing, NAME it (Skibidi Toilet, Squidward screaming, Hello Kitty edit, FF7 Aerith scene, etc.) or describe it concretely by reading what the meme says.  Use the title as a clue.  EVen if the meme is offensive (i.e. mentions a derogative term such as goyim, the n word, etc.)
- If reaction clip: what specifically is the streamer reacting to? Don't say "a meme" — describe the meme
- The streamer's exact action — words spoken, expression, body language at the punchline
- Exact moment the payoff lands

# Step 2: Score viral potential

- Hook strength (would a thumb stop scrolling in first 1-3s?)
- Specificity — is this a one-off banger or a generic "haha streamer reacts" clip?
- Replayability
- Share-ability (would someone tag a friend?)
- Gen Z/Alpha cultural fit (chaotic energy, deadpan, fails, unexpected wholesome, "him cooking" moments)

# Step 3: Write captions that reference the SPECIFICS from Step 1

## What actually works on viral clipper accounts right now:

✅ "not @kaicenat being scared of a SQUIDWARD meme 😭"
✅ "the way he just stops talking when the screaming starts"
✅ "@xqc reacting to his own moderators clip"
✅ "him watching this and slowly realizing it's about him 💀"
✅ "bro went silent for 4 whole seconds"
✅ "POV: you press play on a meme and it actually scares you"
✅ "not the spiritual journey from 0:00 to 0:15 ☠️"

Every one references something specific — the meme, the timing, the exact reaction.

## What doesn't work (avoid this slop):

❌ "the chaotic energy is too real 💀"  — applies to anything
❌ "my last remaining brain cell trying to survive the week"  — overused, no content link
❌ "the level of chaos is unmatched"  — pure vibe filler
❌ "this is Gen Z humor in a nutshell"  — meta, lazy
❌ "him being unhinged for X seconds"  — empty phrasing
❌ Anything that could caption 80% of clips on the platform

## Voice rules

- Lowercase casual is default. ALL CAPS only for one-word emphasis ("BRO" "STOP" "PLEASE")
- One emoji that matches the actual emotion. 💀 😭 🔥 ☠️ 🤯 — pick one, two max
- Do NOT use "no cap" / "fr fr" / "ate" / "slay" — most current top clipper accounts skip the slang and let observational specificity carry it. Forced slang reads cringe.
- Reaction-style openers land: "not him...", "the way she...", "POV:...", "bro...", "him being..."
- Always credit @{{ $('Carry Metadata').item.json.broadcaster_login }}
- Hashtags: streamer-specific first (#{{ $('Carry Metadata').item.json.broadcaster_login }} #{{ $('Carry Metadata').item.json.broadcaster_login }}clips), then niche (game/category), then broad (#fyp #foryou #viral #twitch #twitchclips)
- YouTube tags: 8-12 lowercase, no #, mix streamer+niche+broad. Search tags ≠ display hashtags
- X: "(via @{{ $('Carry Metadata').item.json.broadcaster_login }})" parenthetical credit

